const tallyBody = $items("Webhook Tally")[0].json.body || {};
const isTally = !!tallyBody.data?.fields;

function escapeHtml(unsafe) {
    if (!unsafe) return '';
    return String(unsafe).replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;").replace(/'/g, "&#039;");
}

function escapeAttr(unsafe) {
    if (!unsafe) return '';
    return String(unsafe).replace(/"/g, "&quot;").replace(/'/g, "&#039;");
}

function safeUrl(unsafeUrl) {
    if (!unsafeUrl) return '';
    const u = String(unsafeUrl).trim();
    if (u.startsWith('http://') || u.startsWith('https://')) return escapeAttr(u);
    return '';
}

function getValue(tallyLabel, directKey) {
  if (isTally) {
    let f = tallyBody.data.fields.find(x => x.label.toLowerCase().includes(tallyLabel.toLowerCase()));
    if (!f) return '';
    if (f.type === 'FILE_UPLOAD' && Array.isArray(f.value) && f.value.length > 0) return f.value[0].url;
    return f.value || '';
  }
  return tallyBody[directKey] || '';
}

