// Build Gemini API payload from webhook data
const body = $json.body || $json;
const prompt = 'Atua como Copywriter Senior portugues. Cria uma headline e uma subheadline de ALTA CONVERSAO para uma landing page portuguesa, baseando-te nestes dados do negocio: ' + JSON.stringify(body) + ' Regras: headline com menos de 80 caracteres, subheadline com menos de 160, portugues europeu, sem cliches como excelencia ou sucesso.';

const geminiPayload = {
  contents: [{
    parts: [{
      text: prompt
    }]
  }],
  generationConfig: {
    temperature: 0.85,
    maxOutputTokens: 512,
    responseMimeType: 'application/json',
    responseSchema: {
      type: 'OBJECT',
      properties: {
        headline: { type: 'STRING' },
        subheadline: { type: 'STRING' }
      },
      required: ['headline', 'subheadline']
    }
  }
};

return { json: { ...body, geminiPayload: geminiPayload } };
